from string_utils.validation import is_email

def test__is_email():
    # Test cases where email may be affected due to the mutant's condition change
    test_inputs = [
        '"valid.email@domain.com"',  # this should pass in the baseline, should pass in mutant too
        '"invalid.email@"'            # this should fail in the baseline, may pass in the mutant
    ]

    for input_email in test_inputs:
        output = is_email(input_email)
        print(f"input: {input_email}, output: {output}")
